mapper.select:
SELECT b.board_id, b.title, b.created_at, b.view_count, m.nickname from board b inner join member m ON b.member_id = m.member_id
AND b.is_deleted = 0
and b.board_id = #{board_id}
and b.member_id = #{member_id}
order by b.board_id DESC

mapper.update:
update board 
   set title = #{title}, content = #{content}
where board_id = #{board_id}

mapper.delete:
update board
   set is_deleted = '1'
where board_id = #{board_id}
